sql:
SELECT name_full, accreditation
FROM universities
WHERE country = 'USA' AND enrollment > 50000;

SELECT name_full, motto, accreditation, city, state, country
FROM universities
WHERE country = 'USA';

SELECT name_full, city, state, country, enrollment, type, accreditation
FROM universities
WHERE state = 'TX' AND type = 'Private' AND enrollment > 6000;

SELECT name_full, city, state
FROM universities
WHERE country = 'USA';

SELECT country, PI() * POWER(avg_enrollment, 2) AS area_like_value
FROM (
    SELECT country, AVG(enrollment) AS avg_enrollment
    FROM universities
    GROUP BY country
) AS subquery;

SELECT DISTINCT name_full
FROM universities
WHERE country = 'USA';

SELECT name_full, city, state
FROM universities
WHERE city IS NULL OR state IS NULL;

SELECT country, COUNT(*)
FROM universities
GROUP BY country;

external_knowledge:
- 'urban areas' refers to cities;
- 'higher learning institution' refers to universities;
- 'populous' refers to the population of the city;
- 'average number of students attending these educational centers' refers to the average enrollment in universities.

sql:
SELECT MAX(enrollment) AS largest_student_body
FROM universities
WHERE state = 'NY';

SELECT COUNT(DISTINCT university_id) 
FROM university_locations 
WHERE main_campus = 1;

